1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	};
21	
22	const FIRST_INSURANCE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	
31	function itemBasePremium(item: QuoteItem): number {
32	  return BASE_PREMIUM[item.type] ?? 0;
33	}
34	
35	function itemSurcharges(item: QuoteItem): number {
36	  const base = itemBasePremium(item);
37	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
38	  const highEnchantmentSurcharge =
39	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
40	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
41	      : 0;
42	  return curseSurcharge + highEnchantmentSurcharge;
43	}
44	
45	function priceQuoteStep(
46	  step: QuoteStep,
47	  yearsWithMHPCO: number,
48	): { premium: number } {
49	  const policyBase = step.items.reduce(
50	    (sum, item) => sum + itemBasePremium(item),
51	    0,
52	  );
53	  const itemSurchargeTotal = step.items.reduce(
54	    (sum, item) => sum + itemSurcharges(item),
55	    0,
56	  );
57	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
58	  const loyaltyDiscount =
59	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
60	      ? policyBase * LOYALTY_DISCOUNT_RATE
61	      : 0;
62	  const premium = Math.ceil(
63	    policyBase +
64	      itemSurchargeTotal +
65	      firstInsurance -
66	      loyaltyDiscount +
67	      PROCESSING_FEE,
68	  );
69	  return { premium };
70	}
71	
72	export function runScenario(scenario: Scenario): {
73	  results: { premium: number }[];
74	} {
75	  const results = scenario.steps.map((step) =>
76	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO),
77	  );
78	  return { results };
79	}
